+import { isRelation } from '../relation/utils/is-relation';
+import type { Relation } from '../relation/types';
+import type { Schema } from '../storage/types';
+import type { Trait, TraitRecord } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type AspectInput = Trait | Aspect;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+};
+
+export type AspectRecord<T extends Aspect> = T extends Aspect<infer Traits>
+    ? UnionToIntersection<TraitRecord<Traits[number]>>
+    : never;
+
+type UnionToIntersection<T> = (T extends unknown ? (value: T) => void : never) extends (
+    value: infer Result
+) => void
+    ? Result
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<FlattenAspectInputs<T>> {
+    const traits: Trait[] = [];
+    const fieldNames = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input];
+        for (const constituent of constituents) {
+            if (isRelation(constituent)) {
+                throw new Error('Aspects cannot contain relations');
+            }
+
+            const trait = constituent as Trait;
+            const traitSchema = trait.schema as Schema;
+            if (typeof traitSchema === 'object') {
+                for (const field of Object.keys(traitSchema)) {
+                    if (fieldNames.has(field)) {
+                        throw new Error(`Aspect field "${field}" is defined by more than one trait`);
+                    }
+                    fieldNames.add(field);
+                    schema[field] = (traitSchema as Record<string, unknown>)[field];
+                }
+            }
+            traits.push(trait);
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+    }) as Aspect<FlattenAspectInputs<T>>;
+}
+
+type FlattenAspectInput<T> = T extends Aspect<infer Traits> ? Traits[number] : T extends Trait ? T : never;
+type FlattenAspectInputs<T extends readonly AspectInput[]> = {
+    [K in keyof T]: FlattenAspectInput<T[K]>;
+};
+
+export function getAspectTraitValue(aspect: Aspect, value: Record<string, unknown>, trait: Trait) {
+    const schema = trait.schema as Schema;
+    if (typeof schema !== 'object') return value;
+
+    const result: Record<string, unknown> = {};
+    for (const field of Object.keys(schema)) {
+        if (field in value) result[field] = value[field];
+    }
+    return result;
+}
+
+export function expandAspectInputs(inputs: readonly AspectInput[]): Trait[] {
+    return inputs.flatMap((input) => (isAspect(input) ? input.traits : [input]));
+}
